#include <stdio.h>
#include <stdbool.h>
#define MAX 1000000
bool isPrime[MAX + 1];
void sieveOfEratosthenes() {
    for (int i = 0; i <= MAX; i++) isPrime[i] = true;
    isPrime[0] = isPrime[1] = false;
    for (int p = 2; p * p <= MAX; p++) {
        if (isPrime[p]) {
            for (int i = p * p; i <= MAX; i += p) isPrime[i] = false;
        }
    }
}
int countValidPairs(int arr[], int n) {
    int count = 0;
    for (int i = 0; i < n; i++) {
        for (int j = i + 1; j < n; j++) {
            int xor = arr[i] ^ arr[j];
            for (int p1 = 2; p1 <= xor / 2; p1++) {
                if (isPrime[p1] && isPrime[xor - p1] && (p1 % 2 == (xor - p1) % 2)) {
                    count++;
                    break;
                }
            }
        }
    }
    return count;
}
int main() {
    sieveOfEratosthenes();
    int t;
    scanf("%d", &t);
    while (t--) {
        int n;
        scanf("%d", &n);
        int arr[n];
        for (int i = 0; i < n; i++) scanf("%d", &arr[i]);
        printf("%d\n", countValidPairs(arr, n));
    }
    return 0;
}

